noncompliant:
public class Foo
{
    private int x;

    public Foo(int x)
    {
        this.x = x; // Noncompliant: field is only assigned in constructor
    }
}

compliant:
public class Foo
{
    private readonly int x;

    public Foo(int x)
    {
        this.x = x; // Compliant: field is marked as readonly
    }
}
